import machine
import time
import network
from umqtt.simple import MQTTClient

# Wi-Fi configuration
WIFI_SSID = "your_wifi_ssid"
WIFI_PASSWORD = "your_wifi_password"

# MQTT configuration
MQTT_BROKER = "your_mqtt_broker_ip"  # e.g., "192.168.1.100" or "broker.hivemq.com"
MQTT_CLIENT_ID = "esp32_temp_sensor_01"
MQTT_TOPIC = "sensors/temp"
PUBLISH_INTERVAL_SECONDS = 30

# --- Sensor setup (simulate for this example) ---
# For a real sensor, you would initialize it here (e.g., DHT11, DS18B20, etc.)
# and then read its value in the get_temperature() function.
# This example simulates a temperature sensor with random values.
import random
def get_temperature():
    """Simulates reading temperature from a sensor."""
    return random.uniform(20.0, 30.0)

# --- Wi-Fi Connection ---
def connect_wifi():
    print("Connecting to WiFi...")
    sta_if = network.WLAN(network.STA_IF)
    sta_if.active(True)
    sta_if.connect(WIFI_SSID, WIFI_PASSWORD)
    while not sta_if.isconnected():
        print(".", end="")
        time.sleep(1)
    print("\nWiFi Connected!")
    print("IP Address:", sta_if.ifconfig()[0])
    return sta_if

# --- Main Program ---
def main():
    connect_wifi()

    print(f"Connecting to MQTT broker: {MQTT_BROKER}")
    client = MQTTClient(MQTT_CLIENT_ID, MQTT_BROKER)
    client.connect()
    print("Connected to MQTT broker.")

    try:
        while True:
            temperature = get_temperature()
            msg = f"{temperature:.2f}"
            print(f"Publishing to topic '{MQTT_TOPIC}': {msg}")
            client.publish(MQTT_TOPIC, msg)

            time.sleep(PUBLISH_INTERVAL_SECONDS)

    except KeyboardInterrupt:
        print("Program interrupted. Disconnecting MQTT...")
        client.disconnect()
    except Exception as e:
        print(f"An error occurred: {e}")
        client.disconnect()
    finally:
        print("Disconnected from MQTT and exiting.")

if __name__ == "__main__":
    main()